   422→/// Draft - move a Pace from one Heat to another
   423→///
   424→/// Moves the pace to the destination heat with a new Coronet.
   425→/// All Tack history is preserved, with a new Tack recording the draft.
   426→/// State is NOT changed - draft is a move operation, not a state transition.
   427→pub fn jjrg_draft(gallops: &mut jjrg_Gallops, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
   428→    // Validate positioning mutual exclusivity
   429→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   430→        .iter()
   431→        .filter(|&&x| x)
   432→        .count();
   433→    if position_count > 1 {
   434→        return Err("Only one of --before, --after, or --first may be specified".to_string());
   435→    }
   436→
   437→    // Parse and normalize source coronet
   438→    let source_coronet = Coronet::jjrf_parse(&args.coronet)
   439→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   440→    let source_coronet_key = source_coronet.jjrf_display();
   441→
   442→    // Extract source Firemark from coronet
   443→    let source_firemark = source_coronet.jjrf_parent_firemark();
   444→    let source_firemark_key = source_firemark.jjrf_display();
   445→
   446→    // Parse and normalize destination firemark
   447→    let dest_firemark = Firemark::jjrf_parse(&args.to)
   448→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   449→    let dest_firemark_key = dest_firemark.jjrf_display();
   450→
   451→    // Validate source and destination are different
   452→    if source_firemark_key == dest_firemark_key {
   453→        return Err("Cannot draft pace to same heat".to_string());
   454→    }
   455→
   456→    // Verify source heat exists
   457→    if !gallops.heats.contains_key(&source_firemark_key) {
   458→        return Err(format!("Source heat '{}' not found", source_firemark_key));
   459→    }
   460→
   461→    // Verify destination heat exists
   462→    if !gallops.heats.contains_key(&dest_firemark_key) {
   463→        return Err(format!("Heat '{}' not found", dest_firemark_key));
   464→    }
   465→
   466→    // Verify pace exists in source heat
   467→    {
   468→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
   469→        if !source_heat.paces.contains_key(&source_coronet_key) {
   470→            return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
   471→        }
   472→    }
   473→
   474→    // Validate positioning target if specified
   475→    let insert_position = if let Some(ref before_str) = args.before {
   476→        let target = Coronet::jjrf_parse(before_str)
   477→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   478→        let target_key = target.jjrf_display();
   479→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   480→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   481→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   482→        Some(pos)
   483→    } else if let Some(ref after_str) = args.after {
   484→        let target = Coronet::jjrf_parse(after_str)
   485→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   486→        let target_key = target.jjrf_display();
   487→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   488→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   489→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   490→        Some(pos + 1)
   491→    } else if args.first {
   492→        Some(0)
   493→    } else {
   494→        None // Append to end
   495→    };
   496→
   497→    // Remove pace from source heat
   498→    let source_heat = gallops.heats.get_mut(&source_firemark_key).unwrap();
   499→    let pace_data = source_heat.paces.remove(&source_coronet_key)
   500→        .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
   501→    source_heat.order.retain(|c| c != &source_coronet_key);
   502→
   503→    // Get destination heat and allocate new coronet
   504→    let dest_heat = gallops.heats.get_mut(&dest_firemark_key).unwrap();
   505→    let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
   506→
   507→    // Create new tack recording the draft
   508→    let first_tack = pace_data.tacks.first();
   509→    let draft_note = format!("Drafted from {} in {}.\n\n{}",
   510→        source_coronet_key, source_firemark_key,
   511→        first_tack.map(|t| t.text.as_str()).unwrap_or(""));
   512→
   513→    let draft_tack = jjrg_make_tack(
   514→        first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
   515→        draft_note,
   516→        first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
   517→        first_tack.and_then(|t| t.direction.clone()),
   518→    );
   519→
   520→    // Build new pace with draft tack prepended
   521→    let mut new_tacks = vec![draft_tack];
   522→    new_tacks.extend(pace_data.tacks);
   523→
   524→    let new_pace = jjrg_Pace {
   525→        tacks: new_tacks,
   526→    };
   527→
   528→    // Insert into destination heat
   529→    match insert_position {
   530→        Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
   531→        None => dest_heat.order.push(new_coronet_str.clone()),
   532→    }
   533→    dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
   534→
   535→    // Increment destination seed
   536→    dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
   537→
   538→    Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
   539→}
