   789→/// Furlough a Heat - change status or rename
   790→///
   791→/// Updates heat status (racing/stabled) and/or silks.
   792→/// At least one change must be requested.
   793→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   794→    // Validate at least one option provided
   795→    if !args.racing && !args.stabled && args.silks.is_none() {
   796→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   797→    }
   798→
   799→    // Validate racing/stabled mutual exclusivity
   800→    if args.racing && args.stabled {
   801→        return Err("Cannot specify both --racing and --stabled".to_string());
   802→    }
   803→
   804→    // Validate silks if provided
   805→    if let Some(ref silks) = args.silks {
   806→        if !zjjrg_is_kebab_case(silks) {
   807→            return Err(format!("silks must be kebab-case, got '{}'", silks));
   808→        }
   809→    }
   810→
   811→    // Parse and normalize firemark
   812→    let firemark = Firemark::jjrf_parse(&args.firemark)
   813→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   814→    let firemark_key = firemark.jjrf_display();
   815→
   816→    // Verify Heat exists and check status
   817→    {
   818→        let heat = gallops.heats.get(&firemark_key)
   819→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   820→
   821→        // Check not retired (terminal state)
   822→        if heat.status == jjrg_HeatStatus::Retired {
   823→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   824→        }
   825→
   826→        // Validate racing/stabled request
   827→        if args.racing && heat.status == jjrg_HeatStatus::Racing {
   828→            return Err(format!("Heat '{}' is already racing", firemark_key));
   829→        }
   830→        if args.stabled && heat.status == jjrg_HeatStatus::Stabled {
   831→            return Err(format!("Heat '{}' is already stabled", firemark_key));
   832→        }
   833→    }
   834→
   835→    // Apply status change if requested
   836→    if args.racing {
   837→        // Set status to racing
   838→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
   839→
   840→        // Move heat to front of heats object (index 0) to prioritize it
   841→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   842→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   843→        }
   844→    } else if args.stabled {
   845→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
   846→    }
   847→
   848→    // Apply silks change if requested
   849→    if let Some(silks) = args.silks {
   850→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
   851→    }
   852→
   853→    Ok(())
   854→}
