  1017→    let dest_firemark = Firemark::jjrf_parse(&args.dest_firemark)
  1018→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
  1019→    let dest_firemark_key = dest_firemark.jjrf_display();
  1020→
  1021→    // Validate firemarks are different
  1022→    if source_firemark_key == dest_firemark_key {
  1023→        return Err("Cannot draft paces to same heat".to_string());
  1024→    }
  1025→
  1026→    // Validate both heats exist
  1027→    if !gallops.heats.contains_key(&source_firemark_key) {
  1028→        return Err(format!("Heat '{}' not found", source_firemark_key));
  1029→    }
  1030→    if !gallops.heats.contains_key(&dest_firemark_key) {
  1031→        return Err(format!("Heat '{}' not found", dest_firemark_key));
  1032→    }
  1033→
  1034→    // Validate coronet array is non-empty
  1035→    if args.coronets.is_empty() {
  1036→        return Err("No paces specified for draft".to_string());
  1037→    }
  1038→
  1039→    // Validate all coronets before any mutations
  1040→    let mut normalized_coronets = Vec::new();
  1041→    for coronet_str in &args.coronets {
  1042→        // Parse and normalize coronet
  1043→        let coronet = Coronet::jjrf_parse(coronet_str)
  1044→            .map_err(|e| format!("Invalid coronet '{}': {}", coronet_str, e))?;
  1045→        let coronet_key = coronet.jjrf_display();
  1046→
  1047→        // Verify coronet belongs to source heat
  1048→        let coronet_firemark = coronet.jjrf_parent_firemark();
  1049→        if coronet_firemark.jjrf_display() != source_firemark_key {
  1050→            return Err(format!(
  1051→                "Pace {} does not belong to source heat {}",
  1052→                coronet_key, source_firemark_key
  1053→            ));
  1054→        }
  1055→
  1056→        // Verify pace exists in source heat
  1057→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1058→        if !source_heat.paces.contains_key(&coronet_key) {
  1059→            return Err(format!(
  1060→                "Pace {} not found in heat {}",
  1061→                coronet_key, source_firemark_key
  1062→            ));
  1063→        }
