  1065→        normalized_coronets.push(coronet_key);
  1066→    }
  1067→
  1068→    // All validations passed - now perform the operations
  1069→
  1070→    // Capture source heat info before mutations
  1071→    let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1072→    let source_silks = source_heat.silks.clone();
  1073→    let source_paddock = source_heat.paddock_file.clone();
  1074→
  1075→    // Capture destination heat info
  1076→    let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
  1077→    let dest_silks = dest_heat.silks.clone();
  1078→    let dest_paddock = dest_heat.paddock_file.clone();
  1079→
  1080→    // Draft each pace to destination (preserving order)
  1081→    let mut mappings = Vec::new();
