  1085→            to: dest_firemark_key.clone(),
  1086→            before: None,
  1087→            after: None,
  1088→            first: false, // Append to end to preserve order
  1089→        };
  1090→
  1091→        // Get pace info before drafting (for output)
  1092→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1093→        let pace = source_heat.paces.get(&coronet_key).unwrap();
  1094→        let first_tack = pace.tacks.first();
  1095→        let silks = first_tack.map(|t| t.silks.clone()).unwrap_or_default();
